function initSecJugadores(){document.getElementById('sec-jugadores').innerHTML='<div class="card"><div class="card-head"><h3>Jugadores del club</h3><button class="btn btn-primary" onclick="abrirModalJugadorClub()">+ Nuevo jugador</button></div><div class="card-body"><div id="l-jugadores"></div></div></div>';document.getElementById('sec-player-profile').innerHTML='<button class="btn-back" id="player-back-btn" onclick="volverDeJugador()">&#8592; Volver</button><div id="pp-content"></div>';renderJugadoresClub();insertarModal('m-jugador',modalJugadorHTML());insertarModal('m-med',modalMedicoHTML());insertarModal('m-disc',modalDisciplinaHTML());insertarModal('m-eval',modalEvalHTML());insertarModal('m-conv',modalConvHTML());insertarModal('m-acad',modalAcadHTML());insertarModal('m-season',modalSeasonHTML())}
