async function verJugador(pid,desde){vistaAnterior=desde||'club';jugadorActual=jugadoresClub.find(function(j){return j.id===pid});if(!jugadorActual){var r=await SB.from('club_players').select('*').eq('id',pid).single();jugadorActual=r.data}if(!jugadorActual)return;mostrarSeccion('sec-player-profile');document.getElementById('player-back-btn').textContent=vistaAnterior==='team'?'← Volver al equipo':'← Volver a jugadores';await renderPerfil()}
