    if(j.dominant_foot)h+='<span class="badge badge-blue">'+j.dominant_foot+'</span>';if(j.license_number)h+='<span class="badge badge-purple">'+j.license_number+'</span>';if(j.extracomunitario)h+='<span class="badge badge-amber">Extracom.</span>';if(j.continues_next_season==='si')h+='<span class="badge badge-green">Continua</span>';if(j.continues_next_season==='no')h+='<span class="badge badge-red">No continua</span>';h+='</div>';
    h+='<div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-top:10px;font-size:11px">';h+=_pd2('Nacimiento',(j.birth_date||'—')+(ed?' ('+ed+')':''));h+=_pd2('Lugar nac.',j.birth_place);h+=_pd2('Nacionalidad',j.nationality);h+=_pd2('DNI',j.dni_nie);h+=_pd2('Telefono',j.phone);h+=_pd2('Club origen',j.previous_clubs);h+=_pd2('Alta',j.registration_date);h+=_pd2('Fin derechos',j.end_rights_date);h+=_pd2('Vto. revision',j.medical_review_date);h+='</div></div></div>';
