    h+='<div class="pit" onclick="spt(\'informes\',this)"><span class="pit-icon">&#128203;</span><span class="pit-label">Informes</span><span class="pit-count">'+_pEvals.length+'</span></div>';
    h+='<div class="pit" onclick="spt(\'charlas\',this)"><span class="pit-icon">&#128172;</span><span class="pit-label">Charlas</span><span class="pit-count">'+_pConv.length+'</span></div>';
    h+='<div class="pit" onclick="spt(\'academico\',this)"><span class="pit-icon">&#127891;</span><span class="pit-label">Estudios</span><span class="pit-count">'+_pAcad.length+'</span></div>';
    h+='</div>';
