function getSelectedSeasons(){var chks=document.querySelectorAll('.sf-chk');var todas=false,indices=[];chks.forEach(function(c){if(c.value==='todas'&&c.checked)todas=true;else if(c.checked)indices.push(parseInt(c.value))});if(todas)return _pSeasons.slice();return indices.map(function(i){return _pSeasons[i]}).filter(Boolean)}
function onSeasonFilter(){var todasChk=document.querySelector('.sf-chk[value="todas"]');var others=document.querySelectorAll('.sf-chk:not([value="todas"])');if(todasChk&&todasChk.checked){others.forEach(function(c){c.checked=true})}renderDynamicStats()}
function renderDynamicStats(){var ss=getSelectedSeasons();var el=document.getElementById('pp-dynamic');if(!el)return;var h='';if(ss.length>0){h+='<div class="card" style="margin-bottom:12px"><div class="card-body" style="padding:12px 20px;overflow-x:auto"><table class="tbl" style="text-align:center;font-size:12px"><thead><tr><th>Temporada</th><th style="text-align:center">Conv.</th><th style="text-align:center">Tit.</th><th style="text-align:center">Supl.</th><th style="text-align:center">Min.</th><th style="text-align:center">Goles</th><th style="text-align:center">Asist.</th><th style="text-align:center">TA</th><th style="text-align:center">TR</th><th style="text-align:center">Val.</th></tr></thead><tbody>';var totals={mp:0,ms:0,min:0,g:0,a:0,ya:0,ra:0,vals:[],count:0};ss.forEach(function(s){var mp=s.matches_played||0,ms=s.matches_started||0,min=s.minutes_played||0,g=s.goals||0,as=s.assists||0,ya=s.yellow_cards||0,ra=s.red_cards||0,v=s.rating;totals.mp+=mp;totals.ms+=ms;totals.min+=min;totals.g+=g;totals.a+=as;totals.ya+=ya;totals.ra+=ra;if(v)totals.vals.push(parseFloat(v));h+='<tr><td style="text-align:left;font-weight:600;color:var(--accent)">'+(s.season_name||'?')+'</td><td style="text-align:center">'+mp+'</td><td style="text-align:center">'+ms+'</td><td style="text-align:center">'+(mp-ms)+'</td><td style="text-align:center;font-weight:600">'+min+'</td><td style="text-align:center;font-weight:700;color:var(--a2)">'+g+'</td><td style="text-align:center">'+as+'</td><td style="text-align:center;color:#fbbf24">'+ya+'</td><td style="text-align:center;color:var(--danger)">'+ra+'</td><td style="text-align:center;font-weight:600">'+(v||'—')+'</td></tr>'});if(ss.length>1){var avgVal=totals.vals.length?(totals.vals.reduce(function(a,b){return a+b},0)/totals.vals.length).toFixed(1):'—';h+='<tr style="border-top:2px solid var(--accent);font-weight:700"><td style="text-align:left;color:var(--tp)">TOTALES</td><td style="text-align:center">'+totals.mp+'</td><td style="text-align:center">'+totals.ms+'</td><td style="text-align:center">'+(totals.mp-totals.ms)+'</td><td style="text-align:center">'+totals.min+'</td><td style="text-align:center;color:var(--a2)">'+totals.g+'</td><td style="text-align:center">'+totals.a+'</td><td style="text-align:center;color:#fbbf24">'+totals.ya+'</td><td style="text-align:center;color:var(--danger)">'+totals.ra+'</td><td style="text-align:center">'+avgVal+'</td></tr>'}h+='</tbody></table></div></div>'}h+='<div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">';if(_pEvals.length)h+='<div class="card" style="margin:0"><div class="card-body" style="padding:14px"><div style="font-size:11px;font-weight:700;color:var(--tp);margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px">Valoracion</div><div style="height:220px"><canvas id="chart-radar"></canvas></div></div></div>';if(ss.length)h+='<div class="card" style="margin:0"><div class="card-body" style="padding:14px"><div style="font-size:11px;font-weight:700;color:var(--tp);margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px">Estadisticas</div><div style="height:220px"><canvas id="chart-stats"></canvas></div></div></div>';h+='</div>';if(ss.length>1&&ss.some(function(s){return s.height_cm||s.weight_kg}))h+='<div class="card" style="margin-bottom:16px"><div class="card-body" style="padding:14px"><div style="font-size:11px;font-weight:700;color:var(--tp);margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px">Evolucion fisica</div><div style="height:180px"><canvas id="chart-growth"></canvas></div></div></div>';el.innerHTML=h;setTimeout(function(){if(typeof destroyCharts==='function')destroyCharts();if(document.getElementById('chart-radar')&&_pEvals.length&&typeof renderRadarEvaluaciones==='function')renderRadarEvaluaciones('chart-radar',_pEvals);if(document.getElementById('chart-stats')&&ss.length&&typeof renderBarrasTemporadas==='function')renderBarrasTemporadas('chart-stats',ss);if(document.getElementById('chart-growth')&&ss.length&&typeof renderEvolucionFisica==='function')renderEvolucionFisica('chart-growth',ss)},80)}
function initPlayerBodyMap(){if(typeof BodyMuscles==='undefined'||!_pMedical.length)return;var container=document.getElementById('pp-bodymap');if(!container)return;container.innerHTML='<div style="display:flex;gap:8px"><div id="pp-bm-front" style="flex:1"></div><div id="pp-bm-back" style="flex:1"></div></div>';var bs=buildBodyState(_pMedical);var BC=BodyMuscles.BodyChart,VS=BodyMuscles.ViewSide;try{new BC(document.getElementById('pp-bm-front'),{view:VS.FRONT,bodyState:bs,showViewLabel:false,onMuscleClick:function(id,name){onPlayerBodyClick(id,name)}});new BC(document.getElementById('pp-bm-back'),{view:VS.BACK,bodyState:bs,showViewLabel:false,onMuscleClick:function(id,name){onPlayerBodyClick(id,name)}})}catch(e){console.error('BodyMap error:',e)}}
function onPlayerBodyClick(muscleId,muscleName){var nameES=typeof muscleNameES==='function'?muscleNameES(muscleId,muscleName):muscleName;var matches=_pMedical.filter(function(m){var ids=typeof bodyPartToMuscleIds==='function'?bodyPartToMuscleIds(m.body_part):[];return ids.indexOf(muscleId)!==-1});var panel=document.getElementById('pp-bodymap-detail');if(!panel)return;if(!matches.length){panel.innerHTML='<div style="font-weight:600;color:var(--tp);margin-bottom:6px">'+nameES+'</div><p>Sin lesiones en esta zona</p>';return}var h='<div style="font-weight:600;color:var(--tp);margin-bottom:6px">'+nameES+' ('+matches.length+')</div>';matches.forEach(function(m){var stColor=m.status==='activa'?'badge-red':m.status==='en_tratamiento'?'badge-amber':m.status==='en_readaptacion'?'badge-purple':'badge-green';h+='<div style="padding:6px 0;border-bottom:1px solid var(--border)"><div>'+m.description+' <span class="badge '+stColor+'" style="font-size:10px">'+(m.status||'').replace(/_/g,' ')+'</span></div><div style="color:var(--ts2);font-size:11px">'+m.date_start+(m.date_end?' → '+m.date_end:'')+(m.days_out?' | '+m.days_out+' dias':'')+'</div></div>'});panel.innerHTML=h}
function _pd2(l,v){return'<div><span style="color:var(--tm);font-weight:600;text-transform:uppercase;letter-spacing:.5px;font-size:10px">'+l+'</span><div style="color:var(--tp);font-weight:500;margin-top:1px">'+(v||'—')+'</div></div>'}
function _od(l,v){return'<div><span style="color:var(--tm)">'+l+':</span> <span style="color:var(--tp);font-weight:500">'+v+'</span></div>'}
function spt(n,b){document.querySelectorAll('.psec').forEach(function(s){s.classList.remove('active')});document.querySelectorAll('.ptab,.pit').forEach(function(t){t.classList.remove('active')});document.getElementById('ps-'+n).classList.add('active');if(b)b.classList.add('active')}
async function eliminarReg(t,id){if(!confirm('Eliminar?'))return;await SB.from(t).delete().eq('id',id);toast('Eliminado');await renderPerfil()}
function _secTemporadas(ss){return'<div class="psec active" id="ps-temporadas"><div class="card"><div class="card-head"><h3>Historial</h3><button class="btn btn-primary btn-sm" onclick="abrirModalSeason()">+ Temporada</button></div><div class="card-body">'+(ss.length?ss.map(function(s){var t=s.club_teams||{};return'<div class="ti"><div class="ti-dot" style="background:var(--accent)"></div><div class="ti-c"><div class="ti-date">'+s.season_name+'</div><div class="ti-title">'+(t.name||'?')+' '+(t.category?'<span class="cat-badge cat-'+t.category+'">'+t.category+'</span>':'')+'</div><div class="ti-desc">'+(s.position_detail||s.position||'')+' | #'+(s.shirt_number||'—')+' | '+(s.height_cm||'?')+'cm '+(s.weight_kg||'?')+'kg'+(s.role_in_team?' | '+s.role_in_team:'')+'</div><div class="ti-desc">'+(s.matches_played||0)+' PJ, '+(s.goals||0)+' G, '+(s.assists||0)+' A, '+(s.yellow_cards||0)+' TA, '+(s.red_cards||0)+' TR'+(s.rating?' | Val: '+s.rating:'')+'</div></div></div>'}).join(''):'<div class="empty"><p>Sin temporadas</p></div>')+'</div></div></div>'}
function _secContacto(j){var h='<div class="psec" id="ps-contacto"><div class="card"><div class="card-body" style="display:grid;grid-template-columns:1fr 1fr;gap:24px"><div><div class="fsec" style="margin-top:0">Direccion y telefonos</div>'+_pd2('Direccion',j.address)+_pd2('Localidad',j.city)+'<div class="fr">'+_pd2('Provincia',j.province)+_pd2('Pais',j.country)+'</div>'+_pd2('C. Postal',j.postal_code)+_pd2('Telefono',j.phone)+_pd2('Email',j.email)+'<div class="fsec">Redes sociales</div>'+_pd2('Instagram',j.social_instagram)+_pd2('TikTok',j.social_tiktok)+_pd2('Twitter',j.social_twitter)+_pd2('Facebook',j.social_facebook)+_pd2('Web',j.social_web)+'<div class="fsec">Datos economicos</div>'+_pd2('IBAN',j.iban)+_pd2('Titular',j.iban_holder)+_pd2('N. socio',j.member_number)+'<div class="fsec">Otros</div>'+_pd2('Talla ropa',j.clothes_size)+_pd2('N. pie',j.shoe_size)+_pd2('Representante',j.agent_name)+(j.agent_phone?_pd2('Tel. agente',j.agent_phone):'')+_pd2('Tarj. sanitaria',j.health_card_number)+_pd2('Sangre',j.blood_type)+'</div><div><div class="fsec" style="margin-top:0">Tutor 1</div>'+_pd2('Nombre',j.parent1_name)+_pd2('Parentesco',j.parent1_relationship)+_pd2('Profesion',j.parent1_profession)+_pd2('Empresa',j.parent1_company)+_pd2('Nacimiento',j.parent1_birth_date)+_pd2('Lugar nac.',j.parent1_birth_place)+_pd2('Telefono',j.parent1_phone)+_pd2('DNI',j.parent1_dni)+_pd2('Email',j.parent1_email);if(j.parent2_name)h+='<div class="fsec">Tutor 2</div>'+_pd2('Nombre',j.parent2_name)+_pd2('Parentesco',j.parent2_relationship)+_pd2('Profesion',j.parent2_profession)+_pd2('Empresa',j.parent2_company)+_pd2('Telefono',j.parent2_phone)+_pd2('DNI',j.parent2_dni)+_pd2('Email',j.parent2_email);h+='<div class="fsec">Familia</div>'+_pd2('Hermanos',j.num_siblings)+_pd2('Pos. entre herm.',j.sibling_position)+_pd2('Herm. en club',j.siblings_in_club);if(j.family_situation)h+='<div class="fsec">Situacion familiar</div><p style="font-size:12px;color:var(--ts2);line-height:1.6">'+j.family_situation+'</p>';if(j.special_needs)h+='<div class="fsec">Necesidades especiales</div><p style="font-size:12px;color:var(--ts2)">'+j.special_needs+'</p>';h+='</div></div></div></div>';return h}
function _secMedico(j,md){return'<div class="psec" id="ps-medico"><div class="card"><div class="card-head"><h3>Medico</h3><button class="btn btn-primary btn-sm" onclick="abrirModalMed()">+ Registro</button></div><div class="card-body"><div class="fr3" style="margin-bottom:12px">'+_pd2('Sangre',j.blood_type)+_pd2('Alergias',j.allergies||'Ninguna')+_pd2('Seguro',j.medical_insurance)+'</div><div class="fr" style="margin-bottom:16px">'+_pd2('Cronicas',j.chronic_conditions||'Ninguna')+_pd2('Vto. revision',j.medical_review_date)+'</div><div style="display:grid;grid-template-columns:1fr 240px;gap:16px;margin-bottom:16px"><div id="pp-bodymap"></div><div id="pp-bodymap-detail" style="background:var(--bg-deep);border-radius:var(--rs);min-height:150px;padding:12px;font-size:12px;color:var(--ts2)">Haz clic en una zona del cuerpo</div></div>'+(md.length?md.map(function(m){return'<div class="ti"><div class="ti-dot" style="background:'+(m.severity==='grave'?'var(--danger)':m.severity==='moderada'?'var(--warn)':'var(--a2)')+'"></div><div class="ti-c"><div class="ti-date">'+m.date_start+(m.date_end?' → '+m.date_end:' (activa)')+'</div><div class="ti-title">'+m.type+': '+m.description+'</div><div class="ti-desc">'+(m.body_part||'')+(m.severity?' | '+m.severity:'')+(m.days_out?' | '+m.days_out+' dias':'')+'</div><div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_medical\',\''+m.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin historial</p></div>')+'</div></div></div>'}
function _secDisciplina(ds){return'<div class="psec" id="ps-disciplina"><div class="card"><div class="card-head"><h3>Disciplina</h3><button class="btn btn-primary btn-sm" onclick="abrirModalDisc()">+ Registro</button></div><div class="card-body">'+(ds.length?ds.map(function(d){return'<div class="ti"><div class="ti-dot" style="background:'+(d.type==='roja'||d.type==='expulsion'?'var(--danger)':'var(--warn)')+'"></div><div class="ti-c"><div class="ti-date">'+d.date+'</div><div class="ti-title">'+d.type.replace(/_/g,' ')+(d.match_info?' — '+d.match_info:'')+'</div><div class="ti-desc">'+(d.description||'')+(d.matches_suspended?' | '+d.matches_suspended+' p.':'')+'</div><div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_discipline\',\''+d.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin expedientes</p></div>')+'</div></div></div>'}
function _secInformes(ev){return'<div class="psec" id="ps-informes"><div class="card"><div class="card-head"><h3>Informes</h3><button class="btn btn-primary btn-sm" onclick="abrirModalEval()">+ Informe</button></div><div class="card-body">'+(ev.length?ev.map(function(e){return'<div class="ti"><div class="ti-dot" style="background:var(--accent)"></div><div class="ti-c"><div class="ti-date">'+e.date+' — '+(e.season_name||'')+' — '+(e.evaluator_name||'')+'</div><div class="ti-title">'+e.type+'</div><div class="ti-desc" style="display:flex;gap:6px;flex-wrap:wrap;margin-top:4px">'+(e.rating_technical?'<span class="badge badge-blue">Tec:'+e.rating_technical+'</span>':'')+(e.rating_tactical?'<span class="badge badge-purple">Tac:'+e.rating_tactical+'</span>':'')+(e.rating_physical?'<span class="badge badge-green">Fis:'+e.rating_physical+'</span>':'')+(e.rating_mental?'<span class="badge badge-amber">Men:'+e.rating_mental+'</span>':'')+(e.rating_attitude?'<span class="badge badge-red">Act:'+e.rating_attitude+'</span>':'')+(e.rating_overall?'<span class="badge badge-green">Glob:'+e.rating_overall+'</span>':'')+'</div>'+(e.strengths?'<div class="ti-desc"><strong>+</strong> '+e.strengths+'</div>':'')+(e.weaknesses?'<div class="ti-desc"><strong>-</strong> '+e.weaknesses+'</div>':'')+'<div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_evaluations\',\''+e.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin informes</p></div>')+'</div></div></div>'}
function _secCharlas(cv){return'<div class="psec" id="ps-charlas"><div class="card"><div class="card-head"><h3>Charlas</h3><button class="btn btn-primary btn-sm" onclick="abrirModalConv()">+ Charla</button></div><div class="card-body">'+(cv.length?cv.map(function(c){return'<div class="ti"><div class="ti-dot" style="background:var(--a2)"></div><div class="ti-c"><div class="ti-date">'+c.date+' — '+c.type.replace(/_/g,' ')+'</div><div class="ti-title">'+c.subject+'</div>'+(c.summary?'<div class="ti-desc">'+c.summary+'</div>':'')+(c.agreements?'<div class="ti-desc"><strong>Acuerdos:</strong> '+c.agreements+'</div>':'')+'<div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_conversations\',\''+c.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin charlas</p></div>')+'</div></div></div>'}
function _secAcademico(ac){return'<div class="psec" id="ps-academico"><div class="card"><div class="card-head"><h3>Academico</h3><button class="btn btn-primary btn-sm" onclick="abrirModalAcad()">+ Registro</button></div><div class="card-body">'+(ac.length?ac.map(function(a){return'<div class="ti"><div class="ti-dot" style="background:var(--accent)"></div><div class="ti-c"><div class="ti-date">'+(a.school_year||'')+'</div><div class="ti-title">'+(a.school_name||'')+(a.grade?' — '+a.grade:'')+'</div><div class="ti-desc">'+(a.average_grade?'Nota: '+a.average_grade+' | ':'')+(a.performance||'')+'</div><div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_academic\',\''+a.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin registros</p></div>')+'</div></div></div>'}
function _secSelecciones(cu){return'<div class="psec" id="ps-selecciones"><div class="card"><div class="card-head"><h3>Selecciones</h3><button class="btn btn-primary btn-sm" onclick="abrirModalCallup()">+ Convocatoria</button></div><div class="card-body">'+(cu.length?cu.map(function(c){return'<div class="ti"><div class="ti-dot" style="background:var(--warn)"></div><div class="ti-c"><div class="ti-date">'+c.date_start+(c.date_end?' → '+c.date_end:'')+'</div><div class="ti-title">'+c.selection_name+'</div><div class="ti-desc">'+(c.competition||'')+(c.matches_played?' | '+c.matches_played+' p.':'')+'</div><div class="ti-actions"><button class="btn btn-danger btn-sm" onclick="eliminarReg(\'club_player_callups\',\''+c.id+'\')">X</button></div></div></div>'}).join(''):'<div class="empty"><p>Sin convocatorias</p></div>')+'</div></div></div>'}
function modalMedicoHTML(){return'<div class="modal-bg" id="m-med"><div class="modal"><div class="modal-head"><h3>Registro medico</h3><button class="modal-close" onclick="cm(\'m-med\')">&times;</button></div><div class="modal-body"><input type="hidden" id="med-id"><div class="fr"><div class="fg"><label>Tipo *</label><select id="med-type"><option value="lesion">Lesion</option><option value="enfermedad">Enfermedad</option><option value="revision">Revision</option><option value="intervencion">Intervencion</option><option value="rehabilitacion">Rehabilitacion</option><option value="otro">Otro</option></select></div><div class="fg"><label>Gravedad</label><select id="med-sev"><option value="">—</option><option value="leve">Leve</option><option value="moderada">Moderada</option><option value="grave">Grave</option></select></div></div><div class="fr"><div class="fg"><label>Fecha inicio *</label><input type="date" id="med-start"></div><div class="fg"><label>Fecha fin</label><input type="date" id="med-end"></div></div><div class="fg"><label>Descripcion *</label><input id="med-desc"></div><div class="fr"><div class="fg"><label>Zona</label><input id="med-body"></div><div class="fg"><label>Dias baja</label><input type="number" id="med-days"></div></div><div class="fg"><label>Tratamiento</label><textarea id="med-treat"></textarea></div><div class="fg"><label>Profesional</label><input id="med-doc"></div></div><div class="modal-foot"><button class="btn btn-secondary" onclick="cm(\'m-med\')">Cancelar</button><button class="btn btn-success" onclick="guardarMedico()">Guardar</button></div></div></div>'}
